[asy]
import geometry;

unitsize(1 cm);

pair A, B, C, D, E, F, G, M, N;

A = (1,3);
B = (0,0);
C = (4,0);
D = (B + C)/2;
E = (C + A)/2;
F = (A + B)/2;
G = (A + B + C)/3;
M = extension(G, G + B - C, A, B);
N = extension(G, G + B - C, A, C);

draw(A--B--C--cycle);
draw(A--D);
draw(B--E);
draw(C--F);
draw(M--N);

label("$A$", A, dir(90));
label("$B$", B, SW);
label("$C$", C, SE);
label("$D$", D, S);
label("$E$", E, NE);
label("$F$", F, NW);
label("$G$", G, SSW);
label("$M$", M, NW);
label("$N$", N, NE);
[/asy]

